# index_strategy.py

from dataclasses import dataclass
from enum import Enum
from typing import Optional
import hashlib

class IndexTier(Enum):
    HOT  = "hot"   # Last 7 days  - ~1TB  - Fast SSD, full index
    WARM = "warm"  # Last 90 days - ~4TB  - Mixed storage, partial index
    COLD = "cold"  # Historical   - ~5TB  - HDD/Object storage, compressed

@dataclass
class IndexConfig:
    tier: IndexTier
    storage_type: str
    index_fields: list[str]
    compression: bool
    replica_count: int
    refresh_interval: str

    @classmethod
    def hot_config(cls):
        return cls(
            tier=IndexTier.HOT,
            storage_type="nvme_ssd",
            index_fields=["title", "body", "tags", "author", 
                         "timestamp", "category", "metadata.*"],
            compression=False,         # Speed over space
            replica_count=2,           # High availability
            refresh_interval="1s"      # Near real-time
        )

    @classmethod
    def warm_config(cls):
        return cls(
            tier=IndexTier.WARM,
            storage_type="sata_ssd",
            index_fields=["title", "tags", "timestamp", "category"],
            compression=True,          # Balance space/speed
            replica_count=1,
            refresh_interval="30s"
        )

    @classmethod
    def cold_config(cls):
        return cls(
            tier=IndexTier.COLD,
            storage_type="hdd_or_s3",
            index_fields=["title", "timestamp"],  # Minimal index
            compression=True,          # Max compression
            replica_count=1,
            refresh_interval="3600s"   # Hourly refresh fine
        )

class IndexRouter:
    """Routes documents to appropriate tier based on age/access patterns"""

    def __init__(self):
        self.tier_rules = {
            IndexTier.HOT:  lambda doc: doc['age_days'] <= 7,
            IndexTier.WARM: lambda doc: 7 < doc['age_days'] <= 90,
            IndexTier.COLD: lambda doc: doc['age_days'] > 90,
        }
        self.access_promotions = {}  # Track hot cold documents

    def assign_tier(self, document: dict) -> IndexTier:
        """Primary assignment based on document age"""
        for tier, rule in self.tier_rules.items():
            if rule(document):
                return tier
        return IndexTier.COLD

    def promote_document(self, doc_id: str, current_tier: IndexTier) -> Optional[IndexTier]:
        """Promote cold/warm docs to hot tier if access spikes"""
        access_count = self.access_promotions.get(doc_id, 0)

        if current_tier == IndexTier.COLD and access_count > 100:
            return IndexTier.WARM
        if current_tier == IndexTier.WARM and access_count > 1000:
            return IndexTier.HOT
        return None

    def track_access(self, doc_id: str):
        self.access_promotions[doc_id] = \
            self.access_promotions.get(doc_id, 0) + 1
